{"Steps":[],"Env":null,"RemainingFields":{"jobs":{"label":{"runs-on":"ubuntu-latest","permissions":{"contents":"read","pull-requests":"write"},"steps":[{"uses":"actions/labeler@v4","with":{"repo-token":"${{ secrets.GITHUB_TOKEN }}"}},{"uses":"actions/github-script@v6","id":"set-result","with":{"script":"const config = {
  docs: /^docs/,
  bug: /^bug/,
  fix: /^fix/,
  chore: /^chore/,
  feat: /^feat/,
  build: /^build/,
  ci: /^ci/,
  refactor: /^refactor/,
  "breaking-change": /!:/,
};

const labels = Object.entries(config).reduce(
  (acc, cur) => (context.payload.pull_request.title.match(cur[1]) 
    ? [...acc, cur[0]] : acc),
  []
);

if (labels.length > 0) {
  await github.rest.issues.addLabels({
    owner: context.repo.owner,
    repo: context.repo.repo,
    issue_number: context.payload.pull_request.number,
    labels: labels
  });
}
","result-encoding":"string"}}]}},"name":"Labeler","on":["pull_request"]}}
